import { useEffect, useState } from "react";
import { collection, getDocs } from "firebase/firestore";
import { db } from "../data/firebase";
import { useNavigate } from "react-router-dom";
import * as XLSX from "xlsx";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

type EventItem = {
  id: string;
  title?: string;
  date?: string;
  time?: string;
  place?: string;
  teacher?: string;
};
const downloadPDF = (events: EventItem[]) => {
  console.log("PDF CLICKED 🔥");

  if (events.length === 0) {
    alert("No events to export ❌");
    return;
  }

  const doc = new jsPDF();
  // 🔥 BASE64 LOGO (paste here)
  const logo = "data:image/png;base64,";

  // 🔥 ADD LOGO
  doc.addImage(logo, "PNG", 15, 10, 20, 20);


  // 🔥 TITLE CENTER
  doc.setFontSize(16);
  doc.text("Gudiyatham Manavalakkalai Mandram Trust", 105, 15, {
    align: "center",
  });

  doc.setFontSize(12);
  doc.text("Event History Report", 105, 22, {
    align: "center",
  });

  // 🔥 DATE
  doc.setFontSize(10);
  doc.text(
    `Generated on: ${new Date().toLocaleString()}`,
    14,
    30
  );

  // 🔥 TABLE
  const tableColumn = ["Title", "Date", "Time", "Place", "Teacher"];

  const tableRows = events.map((e) => [
    e.title || "",
    e.date || "",
    e.time || "",
    e.place || "",
    e.teacher || "",
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 35,
    styles: { fontSize: 10 },
    headStyles: { fillColor: [255, 153, 51] }, // saffron 🔥
  });

  // 🔥 SAVE
  doc.save("event-history.pdf");
};
const downloadExcel = (events: EventItem[]) => {
  const worksheet = XLSX.utils.json_to_sheet(events);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Events");

  XLSX.writeFile(workbook, "event-history.xlsx");
};
const EventHistory = () => {
  const [events, setEvents] = useState<EventItem[]>([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchEvents = async () => {
      const snapshot = await getDocs(collection(db, "events"));

      const list = snapshot.docs.map((doc) => ({
        id: doc.id,
        ...doc.data(),
      })) as EventItem[];

      const today = new Date();

      // 🔥 FILTER PAST EVENTS ONLY
      const pastEvents = list.filter((e) => {
        const eventDate = new Date(e.date || "");
        return eventDate < today;
      });

      // 🔥 SORT LATEST FIRST
      pastEvents.sort(
        (a, b) =>
          new Date(b.date || "").getTime() -
          new Date(a.date || "").getTime()
      );

      setEvents(pastEvents);
    };

    fetchEvents();
  }, []);
  const downloadCSV = () => {
  if (events.length === 0) return;

  const headers = ["Title", "Date", "Time", "Place", "Teacher"];

  const rows = events.map((e) => [
    e.title,
    e.date,
    e.time,
    e.place,
    e.teacher,
  ]);

  let csvContent =
    "data:text/csv;charset=utf-8," +
    [headers, ...rows]
      .map((row) => row.join(","))
      .join("\n");

  const encodedUri = encodeURI(csvContent);

  const link = document.createElement("a");
  link.setAttribute("href", encodedUri);
  link.setAttribute("download", "event-history.csv");
  document.body.appendChild(link);

  link.click();
};

  return (
    <div className="max-w-3xl mx-auto p-6">
      <button
          onClick={() => navigate("/admin")}
          className="bg-white/30 backdrop-blur-md border border-white/30 px-4 py-2 rounded-lg shadow hover:bg-white/50 transition"
        >
          ⬅ Back
        </button>
      <h1 className="text-2xl font-bold mb-6 text-saffron">
        📜 Event History
      </h1>

      {events.length === 0 ? (
        <p>No past events available</p>
      ) : (
        <div className="space-y-4">
          {events.map((e) => (
            <div
              key={e.id}
              onClick={() => navigate(`/event/${e.id}`)}
              className="bg-white shadow-md p-4 rounded-lg cursor-pointer hover:shadow-lg"
            >
              <h2 className="font-semibold">{e.title}</h2>
              <p className="text-sm text-gray-600">
                📅 {e.date} | ⏰ {e.time} 🟠 {e.title} | 👨‍🏫 {e.teacher}
              </p>
              <p className="text-sm">📍 {e.place}</p>
            </div>
          ))}
        </div>
      )}
      <button
        onClick={() => downloadExcel(events)}
        className="bg-saffron text-white px-4 py-2 rounded mb-4">
          ⬇ Download Excel
      </button>
       <button
        onClick={() => downloadPDF(events)}
        className="bg-red-600 text-white px-4 py-2 rounded mb-4">
            📄 Download PDF
        </button>
        
    </div>
  );
};

export default EventHistory;